{
    margin: 0;
    font-size: 42px;
    line-height: 1;
    letter-spacing: .04em;
    text-transform: uppercase;
    color: var(--white-soft);
}

.brand .subtitle
{
    color: var(--muted);
    font-size: 14px;
}

.run-meta
{
    display: grid;
    gap: 8px;
    min-width: 280px;
    color: var(--muted);
    font-size: 13px;
    text-align: right;
}

.run-meta b
{
    color: var(--text);
    font-weight: 600;
}

.nav-grid
{
    display: grid;
