    flex-direction: column;
    gap: 10px;
    min-height: 116px;
    padding: 16px 18px;
    color: var(--text);
    text-decoration: none;
    background: linear-gradient(180deg, rgba(11,18,37,.95), rgba(7,12,26,.90));
    border: 1px solid rgba(57,213,255,.16);
    box-shadow: var(--glow-panel);
