    overflow: hidden;
}

.nav-card:hover
{
    transform: translateY(-2px);
    border-color: rgba(255,59,107,.36);
    box-shadow: var(--glow-red);
}

.nav-card .tag
{
    color: var(--cyan);
    text-transform: uppercase;
    letter-spacing: .18em;
    font-size: 11px;
}

.nav-card .title
{
    font-size: 22px;
