            return text
                .Replace("&", "&amp;")
                .Replace("<", "&lt;")
                .Replace(">", "&gt;")
                .Replace("\"", "&quot;")
                .Replace("'", "&#39;");
        }

        private static double Clamp01(double value)
            => Math.Max(0, Math.Min(1, value));

        private static string SafeRatio(double value, double max)
        {
            if (max <= 0)
                return "0";

            return Clamp01(value / max).ToString("0.####", CultureInfo.InvariantCulture);
        }
    }
}

using RefactorScope.Core.Metrics;
using RefactorScope.Core.Results;
using System.Text;

namespace RefactorScope.Exporters
{
    /// <summary>
    /// Exports an architectural report in Markdown format.
    ///
    /// The report reflects the same semantic pipeline used in the dashboard:
    ///
    /// Structural Candidates
    ///        ↓
    /// Pattern Similarity
    ///        ↓
    /// Unresolved
    ///
    /// Unresolved candidates represent the final probabilistic classification.
    /// </summary>
    public sealed class MarkdownReportExporter
    {
        public void Export(ConsolidatedReport report, string outputPath)
        {
            var sb = new StringBuilder();

            var architecture = report.GetResult<ArchitecturalClassificationResult>();
            var isolated = report.GetResult<CoreIsolationResult>();
            var coupling = report.GetResult<CouplingResult>();
            var implicitCoupling = report.GetResult<ImplicitCouplingResult>();
            var fitness = report.GetResult<FitnessGateResult>();
            var structure = report.GetResult<ProjectStructureResult>();

            if (architecture == null)
                return;

            var structuralCandidates = report.GetStructuralCandidates();
            var patternSimilarity = report.GetPatternSimilarityCandidates();
            var unresolved = report.GetEffectiveUnresolvedCandidates();

            sb.AppendLine("# 🧬 RefactorScope – Architectural Report");
            sb.AppendLine();
            sb.AppendLine($"📅 **Execution Time:** {report.ExecutionTime:yyyy-MM-dd HH:mm} UTC  ");
            sb.AppendLine($"📂 **Target Scope:** `{report.TargetScope}`  ");
            sb.AppendLine();
            sb.AppendLine("---");
            sb.AppendLine();

            // =====================================================
            // Project Structure
            // =====================================================

            if (structure != null)
            {
                sb.AppendLine("## 📂 Project Structure (Clean)");
                sb.AppendLine();

                sb.AppendLine("```");

                foreach (var line in structure.Lines)
                {
                    sb.AppendLine(line);
                }

                sb.AppendLine("```");
                sb.AppendLine();
                sb.AppendLine("---");
                sb.AppendLine();
            }

            // =====================================================
            // Structural Candidate Analysis
            // =====================================================

            sb.AppendLine("## 🔎 Structural Candidate Analysis (ADR-EXP-007)");
            sb.AppendLine();

            sb.AppendLine($"- **Structural Candidates:** {structuralCandidates.Count}");
            sb.AppendLine($"- **Pattern Similarity:** {patternSimilarity.Count}");
            sb.AppendLine($"- **Unresolved:** {unresolved.Count}");
            sb.AppendLine();

            // =====================================================
            // Architectural Health by Module
            // =====================================================

            sb.AppendLine("---");
            sb.AppendLine();
            sb.AppendLine("## 🏥 Architectural Health by Module");
            sb.AppendLine();

            var modules = architecture.Items.GroupBy(i => i.Folder);

            foreach (var module in modules)
            {
                var total = module.Count();
                if (total == 0) continue;

                var unresolvedCount = unresolved
                    .Count(z => module.Any(m => m.TypeName == z));

                var isolatedCount = isolated?.IsolatedCoreTypes
                    .Count(i => module.Any(m => m.TypeName == i)) ?? 0;

                var fanOut = coupling?.ModuleFanOut
                    .GetValueOrDefault(module.Key) ?? 0;

                var candidateRate = unresolvedCount / (double)total;
                var isolationRate = isolatedCount / (double)total;
                var couplingRate = fanOut / (double)total;
                var coreDensity = module.Count(t => t.Layer == "Core") / (double)total;

                var score = ArchitecturalScoreCalculator.Calculate(
                    module.Key,
                    total,
                    unresolvedCount,
                    isolatedCount,
                    fanOut,
                    module.Count(t => t.Layer == "Core"));

                score = Math.Max(0, Math.Min(100, score));

                var scoreEmoji = score >= 70 ? "🟢"
                                 : score >= 40 ? "🟡"
                                 : "🔴";

                sb.AppendLine($"### {scoreEmoji} {module.Key}");
                sb.AppendLine();
                sb.AppendLine($"- **Score:** `{score:0.0}`");
                sb.AppendLine($"- **Unresolved Candidates:** {(unresolvedCount > 0 ? "🔴" : "🟢")} {unresolvedCount} ({candidateRate:0%})");
                sb.AppendLine($"- **Coupling:** {couplingRate:0.00}");
                sb.AppendLine($"- **Isolation:** {isolationRate:0.00}");
                sb.AppendLine($"- **Core Density:** {coreDensity:0.00}");
                sb.AppendLine();
            }

            // =====================================================
            // Implicit Coupling Analysis
            // =====================================================

            if (implicitCoupling != null && implicitCoupling.Suspicions.Any())
            {
                sb.AppendLine("---");
                sb.AppendLine();
                sb.AppendLine("## ⚠ Implicit Coupling Suspicion");
                sb.AppendLine();

                sb.AppendLine("| Type | Module | Target Module | Fan-Out | Fan-In | Dominance | Volume |");
                sb.AppendLine("|------|--------|---------------|--------|--------|-----------|--------|");

                foreach (var s in implicitCoupling.Suspicions)
                {
                    sb.AppendLine(
                        $"| {s.TypeName} | {s.Module} | {s.TargetModule} | {s.FanOut} | {s.FanIn} | {s.Dominance:0.00} | {s.Volume} |");
                }

                sb.AppendLine();
                sb.AppendLine("Possible architectural coupling detected based on structural heuristics.");
                sb.AppendLine("Manual inspection is recommended.");
                sb.AppendLine();
            }

            // =====================================================
            // Architectural Stability Metrics (Robert Martin)
            // =====================================================

            if (coupling != null)
            {
                sb.AppendLine("---");
                sb.AppendLine();
                sb.AppendLine("## 🧭 Architectural Stability Metrics (Robert Martin)");
                sb.AppendLine();

                sb.AppendLine("| Module | Abstractness (A) | Instability (I) | Distance (D) |");
                sb.AppendLine("|--------|------------------|-----------------|--------------|");

                foreach (var module in coupling.AbstractnessByModule.Keys)
                {
                    var a = coupling.AbstractnessByModule.GetValueOrDefault(module);
                    var i = coupling.InstabilityByModule.GetValueOrDefault(module);
                    var d = coupling.DistanceByModule.GetValueOrDefault(module);

                    sb.AppendLine($"| {module} | {a:0.00} | {i:0.00} | {d:0.00} |");
                }

                sb.AppendLine();
            }

            // =====================================================
            // Fitness Gates
            // =====================================================

            if (fitness != null)
            {
                sb.AppendLine("---");
                sb.AppendLine();
                sb.AppendLine("## 🚦 Fitness Gates");
                sb.AppendLine();

                foreach (var gate in fitness.Gates)
                {
                    var emoji = gate.Status switch
                    {
                        GateStatus.Pass => "🟢",
                        GateStatus.Warn => "🟡",
                        GateStatus.Fail => "🔴",
                        _ => "⚪"
                    };

                    sb.AppendLine($"- {emoji} **{gate.GateName}** {gate.Message}");
                }

                sb.AppendLine();
                sb.AppendLine(fitness.HasFailure
                    ? "🔴 **Architecture NOT ready for CI/CD**"
                    : "🟢 **Architecture ready for CI/CD**");
            }

            sb.AppendLine();
            sb.AppendLine("---");
            sb.AppendLine();

            // =====================================================
            // Metrics Explanation
            // =====================================================

            sb.AppendLine("---");
            sb.AppendLine();
            sb.AppendLine("## 📘 Metrics Explanation");
            sb.AppendLine();

            sb.AppendLine("**Structural Candidates**  ");
            sb.AppendLine("Classes detected with zero or near-zero structural references in the analyzed scope.  ");
            sb.AppendLine("These are potential dead-code candidates based purely on static structural analysis.");
            sb.AppendLine();

            sb.AppendLine("**Pattern Similarity**  ");
            sb.AppendLine("Structural candidates that match known architectural patterns such as:");
            sb.AppendLine("- Dependency Injection usage");
            sb.AppendLine("- Interface-based abstractions");
            sb.AppendLine("- Factory / Strategy structures");
            sb.AppendLine();
            sb.AppendLine("Pattern similarity indicates the class likely participates in a valid architectural pattern.");
            sb.AppendLine("However, it does **not guarantee runtime usage**.");
            sb.AppendLine();

            sb.AppendLine("**Unresolved**  ");
            sb.AppendLine("Candidates that could not be explained by recognized structural patterns.");
            sb.AppendLine("These remain potential dead-code candidates after probabilistic refinement.");
            sb.AppendLine("Manual inspection is recommended.");
            sb.AppendLine();

            sb.AppendLine("**Coupling**  ");
            sb.AppendLine("Average fan-out of types inside the module.");
            sb.AppendLine("Higher values indicate stronger inter-module dependency.");
            sb.AppendLine();

            sb.AppendLine("**Isolation**  ");
            sb.AppendLine("Core-layer types with no incoming structural references.");
            sb.AppendLine("These may indicate incomplete architecture integration.");
            sb.AppendLine();

            sb.AppendLine("**Core Density**  ");
            sb.AppendLine("Proportion of types belonging to the Core architectural layer.");
            sb.AppendLine("Higher density generally indicates stronger domain encapsulation.");
            sb.AppendLine();

            sb.AppendLine("**Architectural Score**  ");
            sb.AppendLine("Composite structural health indicator (0–100) based on:");
            sb.AppendLine("- Coupling impact");
            sb.AppendLine("- Unresolved candidate density");
            sb.AppendLine("- Isolation rate");
            sb.AppendLine("- Core density bonus");
            sb.AppendLine();
            sb.AppendLine("The score is normalized and intended as a heuristic indicator, not a formal proof.");

            // =====================================================
            // Architectural Stability Metrics (Robert Martin)
            // =====================================================

            sb.AppendLine();
            sb.AppendLine("**Architectural Stability Metrics (Robert Martin)**  ");
            sb.AppendLine("The following metrics are derived from the architectural model proposed by Robert C. Martin.");
            sb.AppendLine("They are intended as structural indicators rather than strict architectural rules.");
            sb.AppendLine();

            sb.AppendLine("**Abstractness (A)**  ");
            sb.AppendLine("Represents the proportion of abstractions within a module.");
            sb.AppendLine();
            sb.AppendLine("A = Na / Nc");
            sb.AppendLine();
            sb.AppendLine("Where:");
            sb.AppendLine("- Na = number of abstract types (interfaces or abstract classes)");
            sb.AppendLine("- Nc = total number of types in the module.");
            sb.AppendLine();
            sb.AppendLine("Higher values indicate a more abstract module.");
            sb.AppendLine();

            sb.AppendLine("**Instability (I)**  ");
            sb.AppendLine("Measures how dependent a module is on other modules.");
            sb.AppendLine();
            sb.AppendLine("I = Ce / (Ce + Ca)");
            sb.AppendLine();
            sb.AppendLine("Where:");
            sb.AppendLine("- Ce = outgoing dependencies");
            sb.AppendLine("- Ca = incoming dependencies");
            sb.AppendLine();
            sb.AppendLine("Values closer to 1 indicate modules that depend heavily on other modules.");
            sb.AppendLine();

            sb.AppendLine("**Distance from Main Sequence (D)**  ");
            sb.AppendLine();
            sb.AppendLine("D = | A + I − 1 |");
            sb.AppendLine();
            sb.AppendLine("This metric measures how far a module is from the architectural equilibrium line between abstraction and stability.");
            sb.AppendLine();
            sb.AppendLine("Values close to 0 indicate balanced architecture.");
            sb.AppendLine();
            sb.AppendLine("Higher values indicate architectural tension such as:");
            sb.AppendLine("- overly concrete and rigid modules");
            sb.AppendLine("- overly abstract but unstable modules");
            sb.AppendLine();
            sb.AppendLine("These metrics should be interpreted as architectural signals, not strict violations.");
            sb.AppendLine();


            // =====================================================
            // Implicit Coupling Detection
            // =====================================================

            sb.AppendLine();
            sb.AppendLine("**Implicit Coupling Detection**  ");
            sb.AppendLine("Implicit Coupling identifies classes whose dependencies concentrate towards a specific module or subsystem.");
            sb.AppendLine();
            sb.AppendLine("This heuristic analyzes structural patterns such as:");
            sb.AppendLine("- strong directional dependency concentration");
            sb.AppendLine("- high fan-out towards a single module");
            sb.AppendLine("- asymmetric dependency flows between modules");
            sb.AppendLine();
            sb.AppendLine("A flagged class does not necessarily represent a design problem.");
            sb.AppendLine();
            sb.AppendLine("Typical legitimate cases include:");
            sb.AppendLine("- orchestrators");
            sb.AppendLine("- adapters between subsystems");
            sb.AppendLine("- integration layers");
            sb.AppendLine();
            sb.AppendLine("These signals are intended to highlight areas that may benefit from architectural review.");
            sb.AppendLine();

            sb.AppendLine("_Generated by RefactorScope_");

            File.WriteAllText(outputPath, sb.ToString());
        }
    }
}

using System.Globalization;
using System.Text;

namespace RefactorScope.Exporters
{
    /// <summary>
    /// Renderer responsável pelos gráficos do Parsing Dashboard.
    ///
    /// Objetivo:
    /// Visualizar qualidade e eficiência do parser estrutural.
    ///
    /// Gráficos disponíveis:
    ///
    /// 1. Structure Density
    ///    - Files
    ///    - Types
    ///    - References
    ///
    /// 2. Parsing Quality Radar
    ///    - Classes per File
    ///    - References per Class
    ///    - Confidence
    ///    - Time per Class (eficiência do parser)
    ///
    /// Os gráficos são renderizados como SVG inline
    /// para máxima portabilidade e zero dependência JS.
    /// </summary>
    public class ParsingChartsRenderer
    {
        /// <summary>
        /// Tamanho base dos gráficos.
        /// Mantido consistente com o Structural Dashboard.
        /// </summary>
        const int ChartSize = 320;


        /// <summary>
        /// Renderiza gráfico de densidade estrutural.
        ///
        /// Mostra:
        /// - quantidade de arquivos analisados
        /// - número de tipos detectados
        /// - total de referências estruturais
        ///
        /// Valores absolutos são exibidos acima das barras.
        /// Altura das barras é normalizada pelo maior valor.
        /// </summary>
        public string RenderStructureDensity(
            int files,
            int types,
            int refs)
        {
            string Fmt(double v) => v.ToString(CultureInfo.InvariantCulture);

            int width = ChartSize;
            int height = ChartSize;
            int margin = 40;

            int max = Math.Max(files, Math.Max(types, refs));

            double Normalize(int v) =>
                max == 0 ? 0 : v / (double)max;

            double barMaxHeight = height - margin * 2;

            double barFiles = barMaxHeight * Normalize(files);
            double barTypes = barMaxHeight * Normalize(types);
            double barRefs = barMaxHeight * Normalize(refs);

            double spacing = 70;

            double x1 = margin + spacing;
            double x2 = x1 + spacing;
            double x3 = x2 + spacing;

            var sb = new StringBuilder();

            sb.AppendLine("<div class='chart-container'>");
            sb.AppendLine("<h3>Structure Density</h3>");

            sb.AppendLine(
                $"<svg width='{width}' height='{height}' style='background:#161b22;border-radius:12px'>");

            // eixo
            sb.AppendLine(
                $"<line x1='{margin}' y1='{height - margin}' x2='{width - margin}' y2='{height - margin}' stroke='#30363d'/>");

            // barras
            sb.AppendLine(
                $"<rect x='{Fmt(x1)}' y='{Fmt(height - margin - barFiles)}' width='30' height='{Fmt(barFiles)}' fill='#4f8cff'/>");

            sb.AppendLine(
                $"<rect x='{Fmt(x2)}' y='{Fmt(height - margin - barTypes)}' width='30' height='{Fmt(barTypes)}' fill='#1dd1a1'/>");

            sb.AppendLine(
                $"<rect x='{Fmt(x3)}' y='{Fmt(height - margin - barRefs)}' width='30' height='{Fmt(barRefs)}' fill='#ffd166'/>");

            // valores numéricos
            sb.AppendLine(
                $"<text x='{Fmt(x1 + 15)}' y='{Fmt(height - margin - barFiles - 6)}' text-anchor='middle' fill='#e6edf3' font-size='11'>{files}</text>");

            sb.AppendLine(
                $"<text x='{Fmt(x2 + 15)}' y='{Fmt(height - margin - barTypes - 6)}' text-anchor='middle' fill='#e6edf3' font-size='11'>{types}</text>");

            sb.AppendLine(
                $"<text x='{Fmt(x3 + 15)}' y='{Fmt(height - margin - barRefs - 6)}' text-anchor='middle' fill='#e6edf3' font-size='11'>{refs}</text>");

            // labels
            sb.AppendLine(
                $"<text x='{Fmt(x1 + 15)}' y='{height - 10}' text-anchor='middle' fill='#e6edf3' font-size='11'>Files</text>");

            sb.AppendLine(
                $"<text x='{Fmt(x2 + 15)}' y='{height - 10}' text-anchor='middle' fill='#e6edf3' font-size='11'>Types</text>");

            sb.AppendLine(
                $"<text x='{Fmt(x3 + 15)}' y='{height - 10}' text-anchor='middle' fill='#e6edf3' font-size='11'>Refs</text>");

            sb.AppendLine("</svg>");
            sb.AppendLine("</div>");

            return sb.ToString();
        }



        /// <summary>
        /// Renderiza radar de qualidade do parsing.
        ///
        /// Métricas utilizadas:
        ///
        /// Classes/File
        /// densidade estrutural média.
        ///
        /// Refs/Class
        /// riqueza do grafo estrutural.
        ///
        /// Confidence
        /// plausibilidade heurística do parser.
        ///
        /// Time/Class
        /// eficiência do parser independente do tamanho do projeto.
        ///
        /// Todas as métricas são normalizadas para intervalo [0,1].
        /// </summary>
        public string RenderParsingRadar(
            double classesPerFile,
            double refsPerClass,
            double confidence,
            double timePerClassMs)
        {
            string Fmt(double v) => v.ToString(CultureInfo.InvariantCulture);

            int size = ChartSize;
            int center = size / 2;
            int radius = 110;
            int levels = 4;

            // normalizações empíricas
            double normClasses = Math.Min(1, classesPerFile / 2.0);
            double normRefs = Math.Min(1, refsPerClass / 10.0);
            double normConfidence = Math.Min(1, confidence);

            // 50ms/class considerado limite alto
            double normTime = Math.Min(1, timePerClassMs / 50.0);

            var values = new[]
            {
                normClasses,
                normRefs,
                normConfidence,
                normTime
            };

            var labels = new[]
            {
                "Classes/File",
                "Refs/Class",
                "Confidence",
                "Time/Class"
            };

            var sb = new StringBuilder();

            sb.AppendLine("<div class='chart-container'>");
            sb.AppendLine("<h3>Parsing Quality Radar</h3>");

            sb.AppendLine(
                $"<svg width='{size}' height='{size}' style='background:#161b22;border-radius:12px'>");

            // círculos
            for (int l = 1; l <= levels; l++)
            {
                double rr = radius * (l / (double)levels);

                sb.AppendLine(
                    $"<circle cx='{center}' cy='{center}' r='{Fmt(rr)}' fill='none' stroke='#30363d' stroke-width='1' />");
            }

            // eixos
            for (int i = 0; i < values.Length; i++)
            {
                double angle =
                    (Math.PI * 2 / values.Length) * i - Math.PI / 2;

                double x = center + radius * Math.Cos(angle);
                double y = center + radius * Math.Sin(angle);

                sb.AppendLine(
                    $"<line x1='{center}' y1='{center}' x2='{Fmt(x)}' y2='{Fmt(y)}' stroke='#30363d' />");

                double lx = center + (radius + 22) * Math.Cos(angle);
                double ly = center + (radius + 22) * Math.Sin(angle);

                sb.AppendLine(
                    $"<text x='{Fmt(lx)}' y='{Fmt(ly)}' fill='#e6edf3' font-size='11' text-anchor='middle'>{labels[i]}</text>");
            }

            // pontos do polígono
            var points = new List<string>();

            for (int i = 0; i < values.Length; i++)
            {
                double angle =
                    (Math.PI * 2 / values.Length) * i - Math.PI / 2;

                double rVal = radius * values[i];

                double x = center + rVal * Math.Cos(angle);
                double y = center + rVal * Math.Sin(angle);

                points.Add($"{Fmt(x)},{Fmt(y)}");
            }

            sb.AppendLine(
                $"<polygon points='{string.Join(" ", points)}' fill='rgba(88,166,255,0.35)' stroke='#58a6ff' stroke-width='2'/>");

            sb.AppendLine("</svg>");
            sb.AppendLine("</div>");

            return sb.ToString();
        }
    }
}

using RefactorScope.Core.Abstractions;
using RefactorScope.Core.Model;
using System.Text;

namespace RefactorScope.Exporters;

public sealed class ParsingDashboardExporter
{
    public void Export(IParserResult result, string outputDirectory)
    {
        Directory.CreateDirectory(outputDirectory);

        var htmlPath = Path.Combine(outputDirectory, "ParsingDashboard.html");

        File.WriteAllText(
            htmlPath,
            GenerateHtml(result),
            Encoding.UTF8);
    }


    private string GenerateHtml(IParserResult result)
    {
        var files = result.Model?.Arquivos.Count ?? 0;
        var types = result.Model?.Tipos.Count ?? 0;
        var refs = result.Model?.Referencias.Count ?? 0;

        double executionMs = result.Stats?.ExecutionTime.TotalMilliseconds ?? 0;

        double classesPerFile =
            files == 0 ? 0 : types / (double)files;

        double refsPerClass =
            types == 0 ? 0 : refs / (double)types;

        double timePerClass =
            types == 0 ? 0 : executionMs / types;

        var charts = new ParsingChartsRenderer();

        var sb = new StringBuilder();

        sb.AppendLine("<html><head><meta charset='UTF-8'>");

        #region STYLE

        sb.AppendLine("<style>");

        sb.AppendLine("body { background:#0f1117; color:#e6edf3; font-family:Segoe UI; margin:30px; }");

        sb.AppendLine(".card { display:inline-block; padding:20px; margin:10px; background:#161b22; border-radius:10px; min-width:180px; }");

        sb.AppendLine(".grid { display:grid; grid-template-columns:1fr 1fr; gap:40px; margin-top:40px; }");

        sb.AppendLine("table { border-collapse: collapse; width:100%; margin-top:40px; }");
        sb.AppendLine("th, td { border:1px solid #30363d; padding:8px; }");
        sb.AppendLine("th { background:#21262d; }");

        sb.AppendLine("</style>");

        #endregion

        sb.AppendLine("</head><body>");

        sb.AppendLine("<h1>🧠 Parsing Dashboard</h1>");

        #region KPI CARDS

        sb.AppendLine("<div>");

        sb.AppendLine($"<div class='card'>Parser<br><b>{result.ParserName}</b></div>");
        sb.AppendLine($"<div class='card'>Files<br><b>{files}</b></div>");
        sb.AppendLine($"<div class='card'>Types<br><b>{types}</b></div>");
        sb.AppendLine($"<div class='card'>References<br><b>{refs}</b></div>");

        sb.AppendLine($"<div class='card'>Execution<br><b>{executionMs:0} ms</b></div>");

        sb.AppendLine($"<div class='card'>Classes/File<br><b>{classesPerFile:0.00}</b></div>");
        sb.AppendLine($"<div class='card'>Refs/Class<br><b>{refsPerClass:0.00}</b></div>");
        sb.AppendLine($"<div class='card'>Time/Class<br><b>{timePerClass:0.00} ms</b></div>");
        sb.AppendLine($"<div class='card'>Confidence<br><b>{result.Confidence:P0}</b></div>");

        sb.AppendLine("</div>");

        #endregion


        #region CHARTS

        sb.AppendLine("<div class='grid'>");

        // Structure density
        sb.AppendLine("<div>");
        sb.AppendLine(charts.RenderStructureDensity(files, types, refs));
        sb.AppendLine("</div>");

        // Radar
        sb.AppendLine("<div>");
        sb.AppendLine(
            charts.RenderParsingRadar(
                classesPerFile,
                refsPerClass,
                result.Confidence,
                timePerClass));
        sb.AppendLine("</div>");

        sb.AppendLine("</div>");

        #endregion


        #region TABLE

        sb.AppendLine("<h2 style='margin-top:50px;'>Parsed Types</h2>");

        sb.AppendLine("<table>");
        sb.AppendLine("<tr>");
        sb.AppendLine("<th>Type</th>");
        sb.AppendLine("<th>Namespace</th>");
        sb.AppendLine("<th>File</th>");
        sb.AppendLine("<th>References</th>");
        sb.AppendLine("</tr>");

        foreach (var type in result.Model?.Tipos ?? Enumerable.Empty<TipoInfo>())
        {
            var refsCount =
                result.Model?.Referencias?
                    .Count(r => r.FromType == type.Name) ?? 0;

            sb.AppendLine("<tr>");
            sb.AppendLine($"<td>{type.Name}</td>");
            sb.AppendLine($"<td>{type.Namespace}</td>");
            sb.AppendLine($"<td>{type.DeclaredInFile}</td>");
            sb.AppendLine($"<td>{refsCount}</td>");
            sb.AppendLine("</tr>");
        }

        sb.AppendLine("</table>");

        #endregion


        sb.AppendLine("</body></html>");

        return sb.ToString();
    }
}

using RefactorScope.Core.Abstractions;
using RefactorScope.Core.Context;
using RefactorScope.Core.Results;
using System.Text;

namespace RefactorScope.Exporters
{
    /// <summary>
    /// Exporta a árvore limpa do projeto.
    /// Útil como contexto estrutural para IA.
    /// </summary>
    public class ProjectStructureExporter : IExporter
    {
        public string Name => "projectTree";

        public void Export(
            AnalysisContext context,
            ConsolidatedReport report,
            string outputPath)
        {
            var root = context.Config.RootPath;
            var builder = new StringBuilder();

            builder.AppendLine("# Project Structure");
            builder.AppendLine();

            WriteDirectory(builder, root, "", true);

            var path = Path.Combine(outputPath, "ProjectTree.md");

            File.WriteAllText(path, builder.ToString());
        }

        private void WriteDirectory(StringBuilder builder, string path, string indent, bool isRoot = false)
        {
            var dir = new DirectoryInfo(path);

            if (!isRoot)
                builder.AppendLine($"{indent}├── {dir.Name}");

            var subDirs = dir.GetDirectories()
                .Where(d => !IsIgnored(d.Name))
                .OrderBy(d => d.Name);

            foreach (var sub in subDirs)
            {
                WriteDirectory(builder, sub.FullName, indent + "│   ");
            }
        }

        private bool IsIgnored(string name)
        {
            return name switch
            {
                "bin" => true,
                "obj" => true,
                ".git" => true,
                ".vs" => true,
                _ => false
            };
        }
    }
}

